INSERT INTO task_templates (id, name, description, is_default, is_active) VALUES ('a1b2c3d4-0000-0000-0000-000000000001', 'Monument Self-Storage ERP Implementation', 'Full implementation template for self-storage operators onboarding to Monument ERP. 190 tasks across 5 phases.', true, true);
INSERT INTO task_template_items (id, template_id, sort_order, name, phase, priority, estimated_hours, day_offset, notes) VALUES
  ('b1000000-0000-0000-0000-000000000001', 'a1b2c3d4-0000-0000-0000-000000000001', 1, 'Internal kickoff: review signed SOW and scope', 'Analysis', 'high', 2, 0, 'Internal CSM team aligns on customer goals, contract scope, and key contacts before customer kickoff.'),
  ('b1000000-0000-0000-0000-000000000002', 'a1b2c3d4-0000-0000-0000-000000000001', 2, 'External kickoff call with customer leadership', 'Analysis', 'critical', 2, 1, 'Live video kickoff with customer''s owners, ops director, and IT lead. Confirm timeline and roles.'),
  ('b1000000-0000-0000-0000-000000000003', 'a1b2c3d4-0000-0000-0000-000000000001', 3, 'Send welcome packet and project charter', 'Analysis', 'high', 1, 1, 'Includes implementation roadmap, RACI matrix, and Monument support contact info.'),
  ('b1000000-0000-0000-0000-000000000004', 'a1b2c3d4-0000-0000-0000-000000000001', 4, 'Schedule recurring weekly status meetings', 'Analysis', 'medium', 0.5, 1, '30-minute weekly cadence with customer''s project lead.'),
  ('b1000000-0000-0000-0000-000000000005', 'a1b2c3d4-0000-0000-0000-000000000001', 5, 'Set up customer Slack channel for daily comms', 'Analysis', 'low', 0.5, 1, 'Shared channel between Monument CSM team and customer ops team.'),
  ('b1000000-0000-0000-0000-000000000006', 'a1b2c3d4-0000-0000-0000-000000000001', 6, 'Inventory all customer storage facility locations', 'Analysis', 'high', 4, 2, 'Document every facility: address, square footage, climate-controlled %, gate type, office hours.'),
  ('b1000000-0000-0000-0000-000000000007', 'a1b2c3d4-0000-0000-0000-000000000001', 7, 'Document current management software in use', 'Analysis', 'high', 3, 3, 'Identify legacy ERP (storEDGE, SiteLink, SpareFoot) and version.'),
  ('b1000000-0000-0000-0000-000000000008', 'a1b2c3d4-0000-0000-0000-000000000001', 8, 'Audit current data quality in legacy system', 'Analysis', 'critical', 6, 4, 'Sample tenant records, payment history, and unit roster for completeness and accuracy.'),
  ('b1000000-0000-0000-0000-000000000009', 'a1b2c3d4-0000-0000-0000-000000000001', 9, 'Map current org chart and decision makers', 'Analysis', 'medium', 2, 4, 'Identify who approves pricing changes, who manages tenants, who handles billing escalations.'),
  ('b1000000-0000-0000-0000-000000000010', 'a1b2c3d4-0000-0000-0000-000000000001', 10, 'Review last 12 months of financial statements', 'Analysis', 'high', 4, 5, 'Understand revenue mix, occupancy trends, and seasonality. Establishes ARR baseline.'),
  ('b1000000-0000-0000-0000-000000000011', 'a1b2c3d4-0000-0000-0000-000000000001', 11, 'Document current pricing strategy by location', 'Analysis', 'high', 4, 6, 'Capture base rates, climate-control premiums, promotional discounts, and rate increase cadence.'),
  ('b1000000-0000-0000-0000-000000000012', 'a1b2c3d4-0000-0000-0000-000000000001', 12, 'Document current invoicing workflow', 'Analysis', 'high', 3, 6, 'Billing cycles, late fee policy, auto-pay enrollment %, NSF handling.'),
  ('b1000000-0000-0000-0000-000000000013', 'a1b2c3d4-0000-0000-0000-000000000001', 13, 'Document current gate/access control vendor', 'Analysis', 'critical', 3, 7, 'Identify hardware (PTI, Sentinel, DoorKing) and any cloud integration.'),
  ('b1000000-0000-0000-0000-000000000014', 'a1b2c3d4-0000-0000-0000-000000000001', 14, 'Inventory all unit types and sizes across portfolio', 'Analysis', 'high', 5, 8, '5x5 through 20x40, climate vs non-climate, parking spaces, RV storage.'),
  ('b1000000-0000-0000-0000-000000000015', 'a1b2c3d4-0000-0000-0000-000000000001', 15, 'Document tenant communication channels currently used', 'Analysis', 'medium', 2, 9, 'Email, SMS, postal mail. Open rates, opt-in compliance status.'),
  ('b1000000-0000-0000-0000-000000000016', 'a1b2c3d4-0000-0000-0000-000000000001', 16, 'Review existing tenant portal usage analytics', 'Analysis', 'medium', 2, 9, 'Adoption %, online payment %, online reservation %.'),
  ('b1000000-0000-0000-0000-000000000017', 'a1b2c3d4-0000-0000-0000-000000000001', 17, 'Audit move-in/move-out workflows', 'Analysis', 'high', 3, 10, 'Lease signing process, deposit handling, prorated billing, vacate inspections.'),
  ('b1000000-0000-0000-0000-000000000018', 'a1b2c3d4-0000-0000-0000-000000000001', 18, 'Document current promotional/coupon strategy', 'Analysis', 'medium', 2, 10, 'First month free, military discount, prepay discounts.'),
  ('b1000000-0000-0000-0000-000000000019', 'a1b2c3d4-0000-0000-0000-000000000001', 19, 'Review tax setup by jurisdiction', 'Analysis', 'high', 3, 11, 'Sales tax on rent, occupancy tax.'),
  ('b1000000-0000-0000-0000-000000000020', 'a1b2c3d4-0000-0000-0000-000000000001', 20, 'Document insurance/protection plan offering', 'Analysis', 'medium', 2, 11, 'Tenant protection plan vendor, opt-in vs opt-out, monthly fee tiers.'),
  ('b1000000-0000-0000-0000-000000000021', 'a1b2c3d4-0000-0000-0000-000000000001', 21, 'Audit current reporting and KPI dashboards', 'Analysis', 'medium', 3, 12, 'What does ops actually use daily?'),
  ('b1000000-0000-0000-0000-000000000022', 'a1b2c3d4-0000-0000-0000-000000000001', 22, 'Document compliance and audit requirements', 'Analysis', 'high', 2, 12, 'Lien sale process by state, retention periods, PCI scope.'),
  ('b1000000-0000-0000-0000-000000000023', 'a1b2c3d4-0000-0000-0000-000000000001', 23, 'Review accounts receivable aging detail', 'Analysis', 'high', 3, 13, 'Bucket delinquency: 30/60/90/120+ days. Identify accounts pending lien sale.'),
  ('b1000000-0000-0000-0000-000000000024', 'a1b2c3d4-0000-0000-0000-000000000001', 24, 'Map current third-party integrations in use', 'Analysis', 'high', 3, 14, 'Payment processor, marketing platforms, accounting (QuickBooks/NetSuite), call center.'),
